codigoEjemplo:
// Ejemplo de uso correcto de códigos HTTP

// 200 OK - Operación exitosa
GET /api/v1/customers/123
Response: 200 OK
{
  "id": 123,
  "name": "John Doe"
}

// 201 Created - Recurso creado
POST /api/v1/customers
Request: {"name": "Jane Doe"}
Response: 201 Created
Location: /api/v1/customers/124
{
  "id": 124,
  "name": "Jane Doe"
}

// 204 No Content - Eliminación exitosa
DELETE /api/v1/customers/123
Response: 204 No Content
(sin body)

// 400 Bad Request - Validación falla
POST /api/v1/customers
Request: {"name": ""}  // nombre vacío
Response: 400 Bad Request
{
  "error": "Validation failed",
  "details": ["Name is required"]
}

// 404 Not Found - Recurso no existe
GET /api/v1/customers/999
Response: 404 Not Found
{
  "error": "Customer not found",
  "id": 999
}

// 409 Conflict - Duplicado
POST /api/v1/customers
Request: {"email": "existing@email.com"}
Response: 409 Conflict
{
  "error": "Customer with this email already exists"
}

// 500 Internal Server Error - Error no manejado
GET /api/v1/customers
Response: 500 Internal Server Error
{
  "error": "Database connection failed"
}

// 502 Bad Gateway - Servicio externo falla
GET /api/v1/customers/123/products
Response: 502 Bad Gateway
{
  "error": "Product service unavailable"
}
